// Firebaseの自動収集イベント一覧
const AUTO_EVENTS = [
  'first_open',
  'session_start', 
  'user_engagement',
  'app_remove',
  'app_update',
  'notification_open'
];

// イベントを分類する関数
// 返り値: { type: '自動収集' | 'カスタム', eventName: string }
function classifyEvent(eventName) {
  // AUTO_EVENTSに含まれていれば '自動収集'、そうでなければ 'カスタム' を返してください
  return {
    type: '',
    eventName: eventName
  };
}

// テスト用イベントリスト（変更不要）
const testEvents = [
  'first_open',
  'tutorial_complete',
  'session_start',
  'purchase',
  'notification_open',
  'add_to_cart',
  'app_remove'
];

// 結果出力（変更不要）
testEvents.forEach(eventName => {
  const result = classifyEvent(eventName);
  console.log(`[${result.type}] ${result.eventName}`);
});

// 自動収集イベントの数を出力
const autoCount = testEvents.filter(e => classifyEvent(e).type === '自動収集').length;
console.log(`\n自動収集: ${autoCount}件 / カスタム: ${testEvents.length - autoCount}件`);

