const AUTO_EVENTS = [
  'first_open',
  'session_start',
  'user_engagement',
  'app_remove',
  'app_update',
  'notification_open'
];

function classifyEvent(eventName) {
  return {
    type: AUTO_EVENTS.includes(eventName) ? '自動収集' : 'カスタム',
    eventName: eventName
  };
}

const testEvents = [
  'first_open',
  'tutorial_complete',
  'session_start',
  'purchase',
  'notification_open',
  'add_to_cart',
  'app_remove'
];

testEvents.forEach(eventName => {
  const result = classifyEvent(eventName);
  console.log(`[${result.type}] ${result.eventName}`);
});

const autoCount = testEvents.filter(e => classifyEvent(e).type === '自動収集').length;
console.log(`\n自動収集: ${autoCount}件 / カスタム: ${testEvents.length - autoCount}件`);
